const GOOGLE_SHEETS_WEBHOOK_URL = "https://script.google.com/macros/s/AKfycbwEu6HlAPA8XoTSRCbWDyfNjcr7ae6Cg8SYf-P3K-f40XARiboQWpg66no-2Kf2FMMg/exec";

const LOGO_BASE64 = "";

const PRIZES = [
  { id: 1, label: "5% no seu próximo procedimento", color: "#C89A74", textColor: "#302114" },
  { id: 2, label: "1 escova modelada", color: "#B06835", textColor: "#CABFB4" },
  { id: 3, label: "10% em unha de gel", color: "#CABFB4", textColor: "#302114" },
  { id: 4, label: "10% de desconto no seu próximo procedimento", color: "#C89A74", textColor: "#302114" },
  { id: 5, label: "Não foi dessa vez", color: "#6A4C36", textColor: "#CABFB4" },
  { id: 6, label: "01 sessão de terapia capilar", color: "#B06835", textColor: "#CABFB4" },
];

const NUM_SLICES = PRIZES.length;
const SLICE_ANGLE = 360 / NUM_SLICES;

function WheelCanvas({ rotation }) {
  const size = 320;
  const center = size / 2;
  const radius = center - 4;

  const slices = PRIZES.map((prize, i) => {
    const startAngle = (i * SLICE_ANGLE * Math.PI) / 180;
    const endAngle = ((i + 1) * SLICE_ANGLE * Math.PI) / 180;
    const x1 = center + radius * Math.cos(startAngle);
    const y1 = center + radius * Math.sin(startAngle);
    const x2 = center + radius * Math.cos(endAngle);
    const y2 = center + radius * Math.sin(endAngle);
    const path = `M${center},${center} L${x1},${y1} A${radius},${radius} 0 0,1 ${x2},${y2} Z`;
    const midAngle = startAngle + (SLICE_ANGLE * Math.PI) / 360;
    const textR = radius * 0.65;
    const tx = center + textR * Math.cos(midAngle);
    const ty = center + textR * Math.sin(midAngle);
    const rotDeg = (midAngle * 180) / Math.PI;

    const words = prize.label.split(" ");
    const lines = [];
    let line = "";
    for (const word of words) {
      if ((line + " " + word).trim().length > 12 && line.length > 0) {
        lines.push(line.trim());
        line = word;
      } else {
        line = (line + " " + word).trim();
      }
    }
    if (line) lines.push(line.trim());

    return { prize, path, tx, ty, rotDeg, lines };
  });

  return (
    <svg
      width={size}
      height={size}
      viewBox={`0 0 ${size} ${size}`}
      style={{ transform: `rotate(${rotation - 90}deg)`, transition: "none", filter: "drop-shadow(0 8px 32px rgba(48,33,20,0.35))" }}
    >
      <defs>
        <radialGradient id="wheelGlow" cx="50%" cy="50%" r="50%">
          <stop offset="0%" stopColor="#C89A74" stopOpacity="0.15" />
          <stop offset="100%" stopColor="#302114" stopOpacity="0" />
        </radialGradient>
      </defs>
      {slices.map(({ prize, path, tx, ty, rotDeg, lines }, i) => (
        <g key={i}>
          <path d={path} fill={prize.color} stroke="#302114" strokeWidth="1.5" />
          <g transform={`translate(${tx},${ty}) rotate(${rotDeg + 90})`}>
            {lines.map((l, li) => (
              <text
                key={li}
                x={0}
                y={(li - (lines.length - 1) / 2) * 11}
                textAnchor="middle"
                fill={prize.textColor}
                fontSize="8.5"
                fontFamily="Montserrat, sans-serif"
                fontWeight="700"
                letterSpacing="0.3"
              >
                {l}
              </text>
            ))}
          </g>
        </g>
      ))}
      <circle cx={center} cy={center} r="28" fill="#302114" />
      <circle cx={center} cy={center} r="22" fill="#6A4C36" />
      <circle cx={center} cy={center} r="16" fill="#B06835" />
      <circle cx={center} cy={center} r="10" fill="#C89A74" />
    </svg>
  );
}

export default function App() {
  const [rotation, setRotation] = useState(0);
  const [spinning, setSpinning] = useState(false);
  const [prize, setPrize] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [spun, setSpun] = useState(false);
  const [displayRotation, setDisplayRotation] = useState(0);
  const [form, setForm] = useState({ nome: "", email: "", whatsapp: "" });
  const [sending, setSending] = useState(false);
  const [sent, setSent] = useState(false);
  const animRef = useRef(null);
  const startRot = useRef(0);
  const targetRot = useRef(0);
  const startTime = useRef(null);
  const DURATION = 4200;

  function easeOut(t) {
    return 1 - Math.pow(1 - t, 4);
  }

  function spin() {
    if (spinning || spun) return;
    const prizeIndex = Math.floor(Math.random() * NUM_SLICES);
    const extraSpins = 5 + Math.floor(Math.random() * 4);
    // Each slice i starts at i*60° in SVG space (0° = right/east).
    // The -90° offset in the SVG style means slice 0 starts at the top.
    // The pointer is at the top (0° in wheel CSS space).
    // To land the pointer at the CENTER of slice i, we need to rotate
    // the wheel so that angle (i * SLICE_ANGLE + SLICE_ANGLE/2) aligns with 0°.
    // That means the wheel rotation = -(i * SLICE_ANGLE + SLICE_ANGLE/2).
    // We add full spins and normalise from current position.
    const sliceCenterAngle = prizeIndex * SLICE_ANGLE + SLICE_ANGLE / 2;
    const currentNorm = ((startRot.current % 360) + 360) % 360;
    const targetAngle = (360 - sliceCenterAngle + 360) % 360; // wheel angle needed at rest
    let delta = targetAngle - currentNorm;
    if (delta <= 0) delta += 360; // always spin forward
    targetRot.current = startRot.current + 360 * extraSpins + delta;
    startTime.current = null;
    setSpinning(true);

    function animate(ts) {
      if (!startTime.current) startTime.current = ts;
      const elapsed = ts - startTime.current;
      const t = Math.min(elapsed / DURATION, 1);
      const eased = easeOut(t);
      const current = startRot.current + (targetRot.current - startRot.current) * eased;
      setDisplayRotation(current);

      if (t < 1) {
        animRef.current = requestAnimationFrame(animate);
      } else {
        setDisplayRotation(targetRot.current);
        startRot.current = targetRot.current;
        setSpinning(false);
        setSpun(true);
        setPrize(PRIZES[prizeIndex]);
        setTimeout(() => setShowModal(true), 400);
      }
    }

    animRef.current = requestAnimationFrame(animate);
  }

  function handleSubmit() {
    if (!form.nome || !form.email || !form.whatsapp) return;
    setSending(true);

    // Ação 1: WhatsApp
    const msg = encodeURIComponent(
      `Olá! Meu nome é ${form.nome}, meu e-mail é ${form.email} e acabei de girar a roleta do Dia do Consumidor e ganhei: ${prize.label}. Gostaria de resgatar meu benefício especial!`
    );
    window.open(`https://wa.me/5511994323003?text=${msg}`, "_blank");

    // Ação 2: Google Sheets via Apps Script
    // Usamos mode: "no-cors" pois o Apps Script retorna um redirect que o
    // navegador bloqueia em CORS normal. O dado chega na planilha normalmente.
    if (GOOGLE_SHEETS_WEBHOOK_URL) {
      // GET com params na URL — única abordagem que sobrevive ao redirect
      // do Apps Script sem ser bloqueada pelo browser com mode:no-cors
      const params = new URLSearchParams({
        nome: form.nome,
        email: form.email,
        whatsapp: form.whatsapp,
        premio: prize.label,
        data: new Date().toISOString(),
      });
      fetch(GOOGLE_SHEETS_WEBHOOK_URL + "?" + params.toString(), {
        method: "GET",
        mode: "no-cors",
      }).catch((err) => console.error("Webhook error:", err));
    }

    // Avança imediatamente para a tela de confirmação
    setSending(false);
    setSent(true);
  }

  // Reset total — seguro contra memory leaks: cancela qualquer animação em curso
  function resetGame() {
    if (animRef.current) {
      cancelAnimationFrame(animRef.current);
      animRef.current = null;
    }
    startRot.current = 0;
    targetRot.current = 0;
    startTime.current = null;
    setDisplayRotation(0);
    setSpinning(false);
    setSpun(false);
    setPrize(null);
    setShowModal(false);
    setForm({ nome: "", email: "", whatsapp: "" });
    setSending(false);
    setSent(false);
  }

  const isLoser = prize?.id === 5;

  // Estilo compartilhado do botão "Próxima Cliente"
  const nextClientBtn = {
    width: "100%",
    background: "transparent",
    color: "#CABFB4",
    border: "1.5px solid #6A4C36",
    borderRadius: "50px",
    padding: "13px",
    fontSize: "13px",
    fontWeight: "700",
    fontFamily: "'Montserrat', sans-serif",
    cursor: "pointer",
    letterSpacing: "1.5px",
    textTransform: "uppercase",
    marginTop: "12px",
    transition: "all 0.2s ease",
  };

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(160deg, #302114 0%, #6A4C36 50%, #302114 100%)",
      fontFamily: "'Montserrat', sans-serif",
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      padding: "0 0 32px 0",
      position: "relative",
      overflow: "hidden",
    }}>
      {/* Background orbs */}
      <div style={{
        position: "absolute", top: "-80px", right: "-80px",
        width: "260px", height: "260px", borderRadius: "50%",
        background: "radial-gradient(circle, rgba(200,154,116,0.18) 0%, transparent 70%)",
        pointerEvents: "none",
      }} />
      <div style={{
        position: "absolute", bottom: "100px", left: "-100px",
        width: "300px", height: "300px", borderRadius: "50%",
        background: "radial-gradient(circle, rgba(176,104,53,0.13) 0%, transparent 70%)",
        pointerEvents: "none",
      }} />

      {/* Header */}
      <div style={{
        width: "100%", maxWidth: "420px",
        padding: "28px 24px 16px",
        display: "flex", flexDirection: "column", alignItems: "center", gap: "12px",
      }}>
        <div style={{
          background: "rgba(202,191,180,0.07)",
          borderRadius: "20px",
          padding: "10px 24px",
          border: "1px solid rgba(200,154,116,0.2)",
        }}>
          <img
            src={`data:image/png;base64,${LOGO_BASE64}`}
            alt="Studio Prado"
            style={{ width: "120px", display: "block" }}
          />
        </div>

        <div style={{ textAlign: "center", maxWidth: "320px" }}>
          <p style={{
            color: "#C89A74",
            fontSize: "10px",
            fontWeight: "700",
            letterSpacing: "3px",
            textTransform: "uppercase",
            margin: "0 0 6px 0",
          }}>
            Dia do Consumidor
          </p>
          <p style={{
            color: "#CABFB4",
            fontSize: "13px",
            lineHeight: "1.6",
            margin: 0,
            fontWeight: "400",
          }}>
            Celebre com uma experiência exclusiva.<br />
            <span style={{ color: "#C89A74", fontWeight: "600" }}>Gire a roleta</span> e descubra o seu benefício especial.
          </p>
        </div>
      </div>

      {/* Wheel Section */}
      <div style={{
        position: "relative",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        marginTop: "8px",
      }}>
        {/* Pointer */}
        <div style={{
          position: "absolute",
          top: "-12px",
          zIndex: 10,
          width: 0, height: 0,
          borderLeft: "12px solid transparent",
          borderRight: "12px solid transparent",
          borderTop: "24px solid #C89A74",
          filter: "drop-shadow(0 2px 6px rgba(200,154,116,0.8))",
        }} />

        {/* Outer ring */}
        <div style={{
          borderRadius: "50%",
          padding: "6px",
          background: "conic-gradient(from 0deg, #B06835, #C89A74, #6A4C36, #B06835, #C89A74, #6A4C36, #B06835)",
          boxShadow: "0 0 40px rgba(200,154,116,0.25), 0 0 0 3px rgba(48,33,20,0.8)",
        }}>
          <div style={{ borderRadius: "50%", overflow: "hidden", display: "block" }}>
            <WheelCanvas rotation={displayRotation} />
          </div>
        </div>
      </div>

      {/* Spin Button */}
      <div style={{ marginTop: "28px" }}>
        <button
          onClick={spin}
          disabled={spinning || spun}
          style={{
            background: spinning || spun
              ? "rgba(106,76,54,0.5)"
              : "linear-gradient(135deg, #B06835 0%, #C89A74 50%, #B06835 100%)",
            color: spinning || spun ? "#6A4C36" : "#302114",
            border: "none",
            borderRadius: "50px",
            padding: "16px 44px",
            fontSize: "15px",
            fontWeight: "800",
            fontFamily: "'Montserrat', sans-serif",
            letterSpacing: "2px",
            textTransform: "uppercase",
            cursor: spinning || spun ? "not-allowed" : "pointer",
            boxShadow: spinning || spun ? "none" : "0 4px 24px rgba(200,154,116,0.45), 0 0 0 1px rgba(200,154,116,0.3)",
            transition: "all 0.3s ease",
            transform: spinning || spun ? "scale(0.97)" : "scale(1)",
          }}
        >
          {spinning ? "Girando..." : spun ? "Benefício Revelado ✨" : "Descobrir Benefício"}
        </button>
      </div>

      <p style={{
        color: "rgba(202,191,180,0.4)",
        fontSize: "11px",
        marginTop: "12px",
        letterSpacing: "1px",
      }}>
        {spun ? "" : "Uma chance por cliente"}
      </p>

      {/* Modal */}
      {showModal && prize && (
        <div style={{
          position: "fixed", inset: 0,
          background: "rgba(48,33,20,0.88)",
          display: "flex", alignItems: "flex-end",
          justifyContent: "center",
          zIndex: 100,
          backdropFilter: "blur(6px)",
          animation: "fadeIn 0.3s ease",
        }}
          onClick={(e) => { if (e.target === e.currentTarget && isLoser) setShowModal(false); }}
        >
          <div style={{
            width: "100%", maxWidth: "480px",
            background: "linear-gradient(170deg, #3d2a1a 0%, #2a1a0e 100%)",
            borderRadius: "28px 28px 0 0",
            padding: "32px 24px 40px",
            border: "1px solid rgba(200,154,116,0.25)",
            borderBottom: "none",
            boxShadow: "0 -8px 48px rgba(200,154,116,0.15)",
            animation: "slideUp 0.4s cubic-bezier(0.34,1.56,0.64,1)",
          }}>
            {/* Close handle */}
            <div style={{
              width: "40px", height: "4px",
              background: "rgba(200,154,116,0.3)",
              borderRadius: "2px",
              margin: "0 auto 24px",
            }} />

            {isLoser ? (
              <>
                <div style={{ textAlign: "center", marginBottom: "24px" }}>
                  <div style={{ fontSize: "48px", marginBottom: "12px" }}>🌸</div>
                  <h2 style={{
                    color: "#C89A74",
                    fontSize: "20px",
                    fontWeight: "800",
                    margin: "0 0 12px 0",
                    letterSpacing: "0.5px",
                  }}>
                    Não foi dessa vez
                  </h2>
                  <p style={{
                    color: "#CABFB4",
                    fontSize: "14px",
                    lineHeight: "1.7",
                    margin: 0,
                    fontWeight: "400",
                  }}>
                    Mas no <span style={{ color: "#C89A74", fontWeight: "700" }}>Studio Prado</span> você é sempre especial. Continue acompanhando nossas novidades!
                  </p>
                </div>
                <button onClick={resetGame} style={nextClientBtn}>
                  Próxima Cliente →
                </button>
              </>
            ) : sent ? (
              <div style={{ textAlign: "center", padding: "16px 0" }}>
                <div style={{ fontSize: "56px", marginBottom: "16px" }}>✨</div>
                <h2 style={{ color: "#C89A74", fontSize: "22px", fontWeight: "800", margin: "0 0 10px 0" }}>
                  Benefício registrado!
                </h2>
                <p style={{ color: "#CABFB4", fontSize: "14px", lineHeight: "1.7", margin: "0 0 28px 0" }}>
                  Benefício registrado com sucesso!<br />
                  Aproveite sua experiência no <span style={{ color: "#C89A74", fontWeight: "700" }}>Studio Prado</span>.
                </p>
                <button onClick={resetGame} style={nextClientBtn}>
                  Próxima Cliente →
                </button>
              </div>
            ) : (
              <>
                <div style={{ textAlign: "center", marginBottom: "24px" }}>
                  <div style={{ fontSize: "44px", marginBottom: "10px" }}>🎉</div>
                  <p style={{
                    color: "#C89A74",
                    fontSize: "11px",
                    fontWeight: "700",
                    letterSpacing: "3px",
                    textTransform: "uppercase",
                    margin: "0 0 8px 0",
                  }}>
                    Parabéns!
                  </p>
                  <h2 style={{
                    color: "#CABFB4",
                    fontSize: "13px",
                    fontWeight: "500",
                    margin: "0 0 8px 0",
                  }}>
                    Você acaba de garantir uma experiência exclusiva:
                  </h2>
                  <div style={{
                    background: "linear-gradient(135deg, rgba(176,104,53,0.25), rgba(200,154,116,0.15))",
                    border: "1px solid rgba(200,154,116,0.4)",
                    borderRadius: "14px",
                    padding: "14px 20px",
                  }}>
                    <p style={{
                      color: "#C89A74",
                      fontSize: "17px",
                      fontWeight: "800",
                      margin: 0,
                      lineHeight: "1.4",
                    }}>
                      {prize.label}
                    </p>
                  </div>
                </div>

                <div>
                  <div style={{ display: "flex", flexDirection: "column", gap: "12px", marginBottom: "20px" }}>
                    {[
                      { key: "nome", placeholder: "Seu nome completo", type: "text" },
                      { key: "email", placeholder: "Seu melhor e-mail", type: "email" },
                      { key: "whatsapp", placeholder: "WhatsApp com DDD", type: "tel" },
                    ].map(({ key, placeholder, type }) => (
                      <input
                        key={key}
                        type={type}
                        placeholder={placeholder}
                        value={form[key]}
                        onChange={(e) => setForm({ ...form, [key]: e.target.value })}
                        required
                        style={{
                          background: "rgba(202,191,180,0.06)",
                          border: "1px solid rgba(200,154,116,0.25)",
                          borderRadius: "12px",
                          padding: "14px 16px",
                          color: "#CABFB4",
                          fontSize: "14px",
                          fontFamily: "'Montserrat', sans-serif",
                          outline: "none",
                          transition: "border-color 0.2s",
                        }}
                        onFocus={(e) => e.target.style.borderColor = "rgba(200,154,116,0.7)"}
                        onBlur={(e) => e.target.style.borderColor = "rgba(200,154,116,0.25)"}
                      />
                    ))}
                  </div>

                  <button
                    type="button"
                    onClick={handleSubmit}
                    disabled={sending}
                    style={{
                      width: "100%",
                      background: sending
                        ? "rgba(176,104,53,0.5)"
                        : "linear-gradient(135deg, #B06835 0%, #C89A74 100%)",
                      color: "#302114",
                      border: "none",
                      borderRadius: "50px",
                      padding: "16px",
                      fontSize: "14px",
                      fontWeight: "800",
                      fontFamily: "'Montserrat', sans-serif",
                      letterSpacing: "1.5px",
                      textTransform: "uppercase",
                      cursor: sending ? "not-allowed" : "pointer",
                      boxShadow: sending ? "none" : "0 4px 20px rgba(176,104,53,0.4)",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      gap: "10px",
                    }}
                  >
                    {sending ? (
                      <>
                        <span style={{
                          width: "16px", height: "16px",
                          border: "2px solid rgba(48,33,20,0.3)",
                          borderTop: "2px solid #302114",
                          borderRadius: "50%",
                          display: "inline-block",
                          animation: "spin360 0.7s linear infinite",
                        }} />
                        Registrando...
                      </>
                    ) : "Resgatar Benefício →"}
                  </button>

                  <p style={{
                    color: "rgba(202,191,180,0.4)",
                    fontSize: "11px",
                    textAlign: "center",
                    marginTop: "12px",
                  }}>
                    Seus dados são confidenciais e protegidos.
                  </p>
                </div>
              </>
            )}
          </div>
        </div>
      )}

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Montserrat:wght@400;600;700;800&display=swap');
        @keyframes fadeIn { from { opacity: 0 } to { opacity: 1 } }
        @keyframes slideUp { from { transform: translateY(100%) } to { transform: translateY(0) } }
        @keyframes spin360 { from { transform: rotate(0deg) } to { transform: rotate(360deg) } }
        input::placeholder { color: rgba(202,191,180,0.35); }
        * { box-sizing: border-box; }
      `}</style>
    </div>
  );
}
